export type TemplateCategory =
  | 'nextjs'
  | 'express'
  | 'nestjs'
  | 'static'
  | 'python'
  | 'go'
  | 'database'
  | 'fullstack'
  | 'custom'
  | 'cms'
  | 'nocode'
  | 'analytics'
  | 'application'
  | 'development'
  | 'infrastructure';

export type AppType = 'app' | 'service' | 'database';

/**
 * Database classification for filtering SQL vs NoSQL databases
 * Only applicable to templates with category: 'database'
 */
export type DbClassification = 'relational' | 'nosql';

export interface EnvHint {
  key: string;
  description: string;
  required: boolean;
  default?: string;
  type: 'string' | 'number' | 'secret';
  /**
   * Optional UI autofill behavior for empty required values.
   * This keeps logic data-driven (template-defined) rather than relying on
   * template-id special cases in the wizard.
   */
  autoFill?: 'server_host' | 'server_host_port' | 'server_http_origin';
  /**
   * If true, this variable is only used during initial installation.
   * Changing it after deployment won't have any effect - the value
   * is stored in the application's database, not read from env vars.
   * Examples: admin email, admin password, admin folder path.
   */
  installTimeOnly?: boolean;
}

export interface TemplateVariable {
  name: string;
  description: string;
  default?: string;
}

export interface VolumeHint {
  name: string;
  path: string;
  description: string;
  backupPriority: 'critical' | 'important' | 'optional';
  backupCommand?: string;
}

export interface PortHint {
  name: string;
  containerPort: number;
  defaultHostPort: number;
  protocol: 'tcp' | 'udp';
  required: boolean;
}

export interface DockerTemplate {
  id: string;
  name: string;
  description: string;
  category: TemplateCategory;
  extraCategories?: TemplateCategory[];
  appType: AppType;
  /**
   * Database classification for SQL vs NoSQL filtering
   * Only set for database templates (category: 'database')
   */
  dbClassification?: DbClassification;
  subcategory?: string;
  requiresBuild: boolean;
  icon: string;
  minMemoryMB: number;
  recommendedPort?: number; // Recommended port to prioritize (e.g., 5432 for PostgreSQL)
  compose: string;
  dockerfile?: string;
  envHints: EnvHint[];
  variables: TemplateVariable[];
  /**
   * Optional framework identifiers this template supports (e.g., ['nextjs', 'rails'])
   * Used to resolve templates based on detected frameworks.
   */
  frameworks?: string[];
  documentation?: string;
  externalAccessInstructions?: string; // Instructions for allowing external access (UFW, security groups, etc.)
  securityNotes?: string; // Security best practices and warnings
  postDeploymentSteps?: string; // Steps to take after deployment
  volumeHints?: VolumeHint[];
  portsHints?: PortHint[];
  /** Shell commands to run on the remote host after mkdir but before docker compose up.
   *  Use {{STACK_DIR}} as a placeholder for the working directory. */
  preDeployCommands?: string[];
}
